$ErrorActionPreference = "Stop"

$scriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$repoRoot = Resolve-Path (Join-Path $scriptDir "..")

Set-Location $repoRoot

$cargo = "$env:USERPROFILE\.cargo\bin\cargo.exe"

& $cargo fmt --all -- --check
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo clippy --all-targets -- -D warnings
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo test
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo test -p dbyte_embed
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo run -q -p dbyte_cli -- test --engine tree
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo run -q -p dbyte_cli -- test --engine vm
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo run -q -p dbyte_cli -- disasm tests\smoke\let_add.dby | Out-Null
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo run -q -p dbyte_cli -- tokens tests\smoke\let_add.dby | Out-Null
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo run -q -p dbyte_cli -- ast tests\smoke\let_add.dby | Out-Null
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
& $cargo run -q -p dbyte_cli -- run --vm --trace tests\smoke\let_add.dby | Out-Null
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }

$cli = Join-Path $repoRoot "target\debug\dbyte.exe"

# Version check
$versionOutput = .\target\debug\dbyte.exe --version
if ($versionOutput -ne 'DByte 9.0.2') {
    throw "Version mismatch: expected 'DByte 9.0.2', got '$versionOutput'"
}

function Normalize-Output($value) {
    return (($value -join "`n") -replace "`r`n", "`n").Trim()
}

function Assert-Equal($actual, $expected, $name) {
    if ($actual -ne $expected) {
        throw "$name failed: expected '$expected', got '$actual'"
    }
}

function Assert-Contains($actual, $expected, $name) {
    $actual = $actual -replace "`r`n", "`n"
    $expected = $expected -replace "`r`n", "`n"
    $indentedExpected = "    " + $expected
    $normalizedActual = $actual -replace "(?m)^    ", ""
    $normalizedExpected = $expected -replace "(?m)^    ", ""
    if (-not $actual.Contains($expected) -and -not $actual.Contains($indentedExpected) -and -not $normalizedActual.Contains($normalizedExpected)) {
        throw "$name failed: expected output to contain '$expected', got '$actual'"
    }
}

function Assert-NormalizedEqual($actual, $expected, $name) {
    $normalizedActual = Normalize-Output $actual
    $normalizedExpected = Normalize-Output $expected
    if ($normalizedActual -ne $normalizedExpected) {
        throw "$name failed: expected '$normalizedExpected', got '$normalizedActual'"
    }
}

function Assert-NotContains($actual, $unexpected, $name) {
    $actualToCheck = $actual
    if ($unexpected -eq 'hardware mutation: yes' -or $unexpected -eq 'first PIC_EOI write performed: yes') {
        $allowedHwSmokeFirePerformed10160 = "EOI write hardware smoke fire`n    performed: one PIC_EOI write to master command port`n    armed: no`n    consumed: yes`n    target command port: PIC_MASTER_COMMAND`n    target value: PIC_EOI`n    PIC_EOI writes this command: 1`n    first PIC_EOI write performed: yes`n    hardware mutation: yes`n    runtime irq active: no"
        $allowedHwSmokeFireBlockedAfterPerformed10160 = "EOI write hardware smoke fire`n    blocked: hardware smoke is not armed`n    armed: no`n    consumed: yes`n    target command port: PIC_MASTER_COMMAND`n    target value: PIC_EOI`n    PIC_EOI writes this command: 0`n    first PIC_EOI write performed: yes`n    hardware mutation: no`n    runtime irq active: no"
        $allowedIdtBindHwSmokeFirePerformed10210 = "Controlled IDT bind one-shot hardware smoke fire`n    performed: one IDT descriptor bind to vector 0x81`n    armed: no`n    consumed: yes`n    target vector: 0x81`n    target handler: inert test stub`n    IDT descriptor binds this command: 1`n    first IDT bind performed: yes`n    hardware mutation: yes`n    runtime irq active: no"
        $allowedIdtBindHwSmokeFireBlockedAfterPerformed10210 = "Controlled IDT bind one-shot hardware smoke fire`n    blocked: hardware smoke is not armed`n    armed: no`n    consumed: yes`n    target vector: 0x81`n    target handler: inert test stub`n    IDT descriptor binds this command: 0`n    first IDT bind performed: yes`n    hardware mutation: no`n    runtime irq active: no"
        $allowedIdtInvokeHwSmokeFirePerformed10230 = "Controlled IDT vector invocation one-shot hardware smoke fire`n    performed: one int 0x81 invocation`n    bind proven this boot: yes`n    armed: no`n    consumed: yes`n    target vector: 0x81`n    target handler: inert test stub`n    interrupt invocations this command: 1`n    inert stub reached: yes`n    first IDT invocation performed: yes`n    manual IDT invocation smoke proven this boot: yes`n    hardware mutation: yes`n    runtime irq active: no"
        $allowedIdtInvokeHwSmokeFireBlockedAfterPerformed10230 = "Controlled IDT vector invocation one-shot hardware smoke fire`n    blocked: invocation smoke is not armed`n    bind proven this boot: yes`n    armed: no`n    consumed: yes`n    target vector: 0x81`n    target handler: inert test stub`n    interrupt invocations this command: 0`n    inert stub reached: yes`n    first IDT invocation performed: yes`n    manual IDT invocation smoke proven this boot: yes`n    hardware mutation: no`n    runtime irq active: no"
        $allowedIrq0WindowFirePerformed10300 = "IRQ0 delivery one-shot window fire`n    finished: one IRQ0 delivery observed`n    state: finished`n    IRQ0 deliveries: 1`n    IRQ0 currently masked: yes`n    STI currently enabled: no`n    original PIC mask restored: yes`n    IF disabled before return: yes`n    hardware mutation: yes`n    runtime irq active: no`n    VGA IRQ0 status: FIRED ONCE / MASKED"
        $allowedIrq0WindowFirePerformedDocs10300 = "IRQ0 delivery one-shot window fire`nfinished: one IRQ0 delivery observed`nstate: finished`nIRQ0 deliveries: 1`nIRQ0 currently masked: yes`nSTI currently enabled: no`noriginal PIC mask restored: yes`nIF disabled before return: yes`nhardware mutation: yes`nruntime irq active: no`nVGA IRQ0 status: FIRED ONCE / MASKED"
        $allowedIrq0TicksFirePerformed10310 = "IRQ0 tick counter window fire`n    finished: eight IRQ0 ticks observed`n    state: finished`n    target ticks: 8`n    observed ticks: 8`n    IRQ0 currently masked: yes`n    STI currently enabled: no`n    original PIC mask restored: yes`n    IF disabled before return: yes`n    hardware mutation: yes`n    runtime irq active: no`n    VGA IRQ0 status: TICKS 0008 / MASKED"
        $allowedIrq0TicksFirePerformedDocs10310 = "IRQ0 tick counter window fire`nfinished: eight IRQ0 ticks observed`nstate: finished`ntarget ticks: 8`nobserved ticks: 8`nIRQ0 currently masked: yes`nSTI currently enabled: no`noriginal PIC mask restored: yes`nIF disabled before return: yes`nhardware mutation: yes`nruntime irq active: no`nVGA IRQ0 status: TICKS 0008 / MASKED"
        $actualToCheck = $actualToCheck.Replace($allowedHwSmokeFirePerformed10160, '')
        $actualToCheck = $actualToCheck.Replace($allowedHwSmokeFireBlockedAfterPerformed10160, '')
        $actualToCheck = $actualToCheck.Replace($allowedIdtBindHwSmokeFirePerformed10210, '')
        $actualToCheck = $actualToCheck.Replace($allowedIdtBindHwSmokeFireBlockedAfterPerformed10210, '')
        $actualToCheck = $actualToCheck.Replace($allowedIdtInvokeHwSmokeFirePerformed10230, '')
        $actualToCheck = $actualToCheck.Replace($allowedIdtInvokeHwSmokeFireBlockedAfterPerformed10230, '')
        $actualToCheck = $actualToCheck.Replace($allowedIrq0WindowFirePerformed10300, '')
        $actualToCheck = $actualToCheck.Replace($allowedIrq0WindowFirePerformedDocs10300, '')
        $actualToCheck = $actualToCheck.Replace($allowedIrq0TicksFirePerformed10310, '')
        $actualToCheck = $actualToCheck.Replace($allowedIrq0TicksFirePerformedDocs10310, '')
    }
    if ($unexpected -eq 'write_pic_port(PIC_MASTER_COMMAND, PIC_EOI)') {
        $actualToCheck = $actualToCheck.Replace('write_pic_port(PIC_MASTER_COMMAND, PIC_EOI);', '')
        $actualToCheck = $actualToCheck.Replace('write_pic_port(PIC_MASTER_COMMAND, PIC_EOI)', '')
    }
    if ($unexpected -eq 'asm!("sti",') {
        $actualToCheck = $actualToCheck.Replace('core::arch::asm!("sti", options(nomem, nostack, preserves_flags));', '')
    }
    if ($unexpected -eq 'int 0x81' -or $unexpected -eq 'int $0x81') {
        $actualToCheck = $actualToCheck.Replace('core::arch::asm!("int 0x81");', '')
        $actualToCheck = $actualToCheck.Replace('performed: one int 0x81 invocation', '')
        $actualToCheck = $actualToCheck.Replace('one int 0x81 invocation', '')
    }
    if ($actualToCheck.Contains($unexpected)) {
        throw "$name failed: expected output not to contain '$unexpected', got '$actual'"
    }
}

function Assert-ContainsInOrder($actual, $expectedParts, $name) {
    $actual = $actual -replace "`r`n", "`n"
    $cursor = 0
    foreach ($part in $expectedParts) {
        $part = $part -replace "`r`n", "`n"
        $index = $actual.IndexOf($part, $cursor)
        $matchedLength = $part.Length
        if ($index -lt 0) {
            $indentedPart = "    " + $part
            $index = $actual.IndexOf($indentedPart, $cursor)
            $matchedLength = $indentedPart.Length
        }
        if ($index -lt 0) {
            $normalizedActual = $actual -replace "(?m)^    ", ""
            $normalizedPart = $part -replace "(?m)^    ", ""
            $index = $normalizedActual.IndexOf($normalizedPart, $cursor)
            $matchedLength = $normalizedPart.Length
        }
        if ($index -lt 0) {
            throw "$name failed: expected to find '$part' after offset $cursor"
        }
        $cursor = $index + $matchedLength
    }
}

function Extract-FunctionBlock($content, $signature) {
    $start = $content.IndexOf($signature)
    if ($start -lt 0) {
        throw "function block not found: $signature"
    }
    $braceStart = $content.IndexOf("{", $start)
    if ($braceStart -lt 0) {
        throw "function block brace not found: $signature"
    }
    $depth = 0
    for ($i = $braceStart; $i -lt $content.Length; $i++) {
        $ch = $content[$i]
        if ($ch -eq "{") {
            $depth++
        }
        elseif ($ch -eq "}") {
            $depth--
            if ($depth -eq 0) {
                return $content.Substring($start, $i - $start + 1)
            }
        }
    }
    throw "function block end not found: $signature"
}

function Expected-File($path) {
    if (-not [System.IO.Path]::IsPathRooted($path)) {
        $path = Join-Path $repoRoot $path
    }
    return ((Get-Content $path -Raw) -replace "`r`n", "`n").Trim()
}

function Invoke-Dbyte {
    param(
        [string[]]$Arguments,
        [string]$WorkingDirectory = $null
    )

    $oldPreference = $ErrorActionPreference
    $ErrorActionPreference = "Continue"
    $oldCwd = Get-Location
    try {
        if ($null -ne $WorkingDirectory) {
            Set-Location $WorkingDirectory
        }
        $output = & $cli @Arguments 2>&1
        $code = $LASTEXITCODE
    }
    finally {
        Set-Location $oldCwd
        $ErrorActionPreference = $oldPreference
    }
    return [PSCustomObject]@{
        Code = $code
        Text = Normalize-Output $output
    }
}

function Invoke-DbyteExact {
    param(
        [string[]]$Arguments,
        [string]$WorkingDirectory = $repoRoot,
        [string]$Executable = $cli
    )

    $psi = [System.Diagnostics.ProcessStartInfo]::new()
    $psi.FileName = $Executable
    $quotedArgs = foreach ($arg in $Arguments) {
        if ($arg -eq "") {
            '""'
        }
        else {
            '"' + $arg.Replace('"', '\"') + '"'
        }
    }
    $psi.Arguments = ($quotedArgs -join " ")
    $psi.WorkingDirectory = (Resolve-Path $WorkingDirectory).Path
    $psi.UseShellExecute = $false
    $psi.RedirectStandardOutput = $true
    $psi.RedirectStandardError = $true
    $process = [System.Diagnostics.Process]::Start($psi)
    $stdout = $process.StandardOutput.ReadToEnd()
    $stderr = $process.StandardError.ReadToEnd()
    $process.WaitForExit()
    return [PSCustomObject]@{
        Code = $process.ExitCode
        Text = Normalize-Output @($stdout, $stderr)
    }
}

function Invoke-DbyteInput {
    param(
        [string[]]$Arguments,
        [string]$InputText,
        [string]$WorkingDirectory = $repoRoot,
        [string]$Executable = $cli,
        [hashtable]$Environment = $null
    )

    $psi = [System.Diagnostics.ProcessStartInfo]::new()
    $psi.FileName = $Executable
    $quotedArgs = foreach ($arg in $Arguments) {
        '"' + $arg.Replace('"', '\"') + '"'
    }
    $psi.Arguments = ($quotedArgs -join " ")
    $psi.WorkingDirectory = (Resolve-Path $WorkingDirectory).Path
    $psi.UseShellExecute = $false
    $psi.RedirectStandardInput = $true
    $psi.RedirectStandardOutput = $true
    $psi.RedirectStandardError = $true
    if ($null -ne $Environment) {
        foreach ($key in $Environment.Keys) {
            $psi.Environment[$key] = [string]$Environment[$key]
        }
    }

    $process = [System.Diagnostics.Process]::Start($psi)
    $process.StandardInput.Write($InputText)
    $process.StandardInput.Close()
    $stdout = $process.StandardOutput.ReadToEnd()
    $stderr = $process.StandardError.ReadToEnd()
    $process.WaitForExit()

    return [PSCustomObject]@{
        Code = $process.ExitCode
        Text = Normalize-Output @($stdout, $stderr)
    }
}

function Git-Status-Short {
    return Normalize-Output (& git status --short 2>&1)
}

function Assert-GitStatus-Unchanged($before, $name) {
    $after = Git-Status-Short
    if ($after -ne $before) {
        throw "$name failed: git status changed from '$before' to '$after'"
    }
}

function Assert-PersonalToolOutput($toolName, $output) {
    switch ($toolName) {
        "hexdump" {
            Assert-Contains $output "hexdump:" "personal hexdump heading"
            Assert-Contains $output "bytes: 12" "personal hexdump size"
            Assert-Contains $output "0000: 4442797465001020" "personal hexdump first row"
            Assert-Contains $output "0008: deadbeef" "personal hexdump second row"
        }
        "bininfo" {
            Assert-Contains $output "bininfo:" "personal bininfo heading"
            Assert-Contains $output "bytes: 9" "personal bininfo size"
            Assert-Contains $output "first8: 0102030444427974" "personal bininfo first bytes"
            Assert-Contains $output "checksum: 482" "personal bininfo checksum"
        }
        "find_bytes" {
            Assert-Contains $output "find_bytes" "personal find bytes heading"
            Assert-Contains $output "data: 00deadbeef00dead01" "personal find bytes data"
            Assert-Contains $output "de_ad: 1" "personal find bytes first pattern"
            Assert-Contains $output "be_ef: 3" "personal find bytes second pattern"
            Assert-Contains $output "one_byte: 8" "personal find bytes single byte"
            Assert-Contains $output "missing: -1" "personal find bytes missing pattern"
        }
        "patch_bytes" {
            Assert-Contains $output "patched: 1" "personal patch bytes marker"
            Assert-Contains $output "patched_hex: 009090909000" "personal patch bytes output"
        }
        "read_u32_table" {
            Assert-Contains $output "u32_table:" "personal u32 table heading"
            Assert-Contains $output "data: 7856341201000000efbeadde" "personal u32 table data"
            Assert-Contains $output "0 -> 305419896" "personal u32 table first row"
            Assert-Contains $output "4 -> 1" "personal u32 table second row"
            Assert-Contains $output "8 -> 3735928559" "personal u32 table third row"
        }
        default {
            throw "unknown personal tool assertion: $toolName"
        }
    }
}

function Bytes-Hex($path) {
    return -join ([System.IO.File]::ReadAllBytes((Resolve-Path $path).Path) | ForEach-Object { $_.ToString("x2") })
}

