    if ($dbyteosSnapshotLogs.Code -ne 0) { throw "dbyteos snapshot logs failed: $($dbyteosSnapshotLogs.Text)" }
    Assert-NormalizedEqual $dbyteosSnapshotLogs.Text $expectedDbyteosSnapshotLogs "dbyteos snapshot logs snapshot"

