    Assert-Contains $dbyteosSysinfoRoot.Text $dbyteosConfigRootHome.Text "dbyteos sysinfo home sync"
    foreach ($profileText in @($dbyteosProfileDirect.Text, $dbyteosStatusReport.Text, $dbyteosSysinfoRoot.Text)) {
